147	// StaticCSRFTokenStore is a single-secret CSRFTokenStore — the token is
148	// generated once at server startup and validated by constant-time compare.
149	type StaticCSRFTokenStore struct {
150		token string
151	}
152	
153	// NewStaticCSRFTokenStore returns a store seeded with a freshly-generated
154	// 32-byte random token.
155	func NewStaticCSRFTokenStore() (*StaticCSRFTokenStore, error) {
156		var buf [32]byte
157		if _, err := rand.Read(buf[:]); err != nil {
158			return nil, fmt.Errorf("csrf: generate token: %w", err)
159		}
160		return &StaticCSRFTokenStore{token: hex.EncodeToString(buf[:])}, nil
161	}
162	
163	// NewStaticCSRFTokenStoreWithToken constructs a store using the supplied
164	// token (used by tests so a deterministic header value can be sent).
165	func NewStaticCSRFTokenStoreWithToken(token string) *StaticCSRFTokenStore {
166		return &StaticCSRFTokenStore{token: token}
167	}
168	
169	// Token returns the stored CSRF token (used by the server to expose it via a
170	// dedicated endpoint or embed it in served HTML).
171	func (s *StaticCSRFTokenStore) Token() string { return s.token }
172	
173	// Validate compares presented to the stored token using a length-equal
174	// constant-time check.
175	func (s *StaticCSRFTokenStore) Validate(presented string) bool {
176		if presented == "" || len(presented) != len(s.token) {
177			return false
178		}
179		var diff byte
180		for i := 0; i < len(s.token); i++ {
181			diff |= s.token[i] ^ presented[i]
182		}
183		return diff == 0
184	}
185	
186	// errCSRF is returned by OperatorPromptSubmit when the CSRF check fails.
187	// The HTTP transport for the GraphQL endpoint surfaces this as a 403; the
188	// resolver itself only emits the error.
189	var errCSRF = errors.New("operator-prompts: CSRF token missing or invalid (status: 403)")
190	
191	// errCrossOrigin is returned by OperatorPromptSubmit when the request carries
192	// an Origin header whose host portion does not match the request Host. This
193	// blocks browser cross-origin POSTs even from a trusted-loopback peer (CSRF
194	// defense in depth alongside the per-session token).
195	var errCrossOrigin = errors.New("operator-prompts: cross-origin request rejected (status: 403)")
196	
197	// promptCapError builds the structured cap-error envelope returned by
198	// operatorPromptSubmit when the prompt body exceeds the configured cap. The
199	// envelope is surfaced inside `errors[].extensions` so the SvelteKit
200	// frontend can show observed/cap bytes without parsing the message string.
201	func promptCapError(observed, cap int) error {
202		return &gqlerror.Error{
203			Message: fmt.Sprintf(
204				"operator-prompts: prompt body exceeds cap: observed %d bytes, cap %d bytes (status: 400)",
205				observed, cap,
206			),
207			Extensions: map[string]any{
208				"code":           "PROMPT_TOO_LARGE",
209				"status":         400,
210				"observed_bytes": observed,
211				"cap_bytes":      cap,
212				"config_hint":    ".ddx/config.yaml:evidence_caps.max_prompt_bytes",
213			},
214		}
215	}
216	
217	// errAutoApproveDenied is returned by OperatorPromptApprove (and is the
218	// reason auto-approve gets demoted to a plain proposed bead inside
219	// OperatorPromptSubmit) when the caller's identity is not on the per-project
220	// allowlist. ts-net identities always hit this path regardless of allowlist
221	// contents (locked Story 15 decision: ts-net peers may not blanket
222	// auto-approve operator prompts).
223	var errAutoApproveDenied = errors.New("operator-prompts: identity not on per-project auto-approve allowlist (status: 403)")
224	
225	// errSubmitDenied is returned by OperatorPromptSubmit when the caller is a
226	// ts-net peer whose identity is not on the per-project allowlist
227	// (web.operator_prompt.allow_identities). Localhost callers are always
228	// allowed to submit because they have already cleared the requireTrusted
229	// loopback gate; ts-net peers carry only network-layer trust, so the
230	// per-project allowlist is the authorization step. Empty allowlist →
231	// every ts-net peer is rejected (the locked Story 15 default that yields a
232	// "ts-net peers see read-only UI" outcome).
233	var errSubmitDenied = errors.New("operator-prompts: ts-net identity not on per-project allow_identities allowlist (status: 403)")
234	
235	// OperatorPromptSubmit implements the operatorPromptSubmit mutation: it
236	// validates the CSRF token from the request header, deduplicates within a
237	// 24h window by idempotency key, and (on first submission) creates a new
238	// operator-prompt bead in the proposed status with an audit event capturing
239	// the originating identity (localhost user OR ts-net WhoIs).
240	func (r *mutationResolver) OperatorPromptSubmit(ctx context.Context, input OperatorPromptSubmitInput) (*OperatorPromptSubmitResult, error) {
241		if r.WorkingDir == "" {
242			return nil, fmt.Errorf("working directory not configured")
243		}
244		if strings.TrimSpace(input.Prompt) == "" {
245			return nil, fmt.Errorf("operator-prompts: prompt is required")
246		}
247		if strings.TrimSpace(input.IdempotencyKey) == "" {
248			return nil, fmt.Errorf("operator-prompts: idempotency key is required")
249		}
250	
251		httpReq := httpRequestFromContext(ctx)
252		if httpReq == nil {
253			// No request context means we cannot enforce CSRF, which is the
254			// whole point of the gate. Refuse rather than fail open.
255			return nil, errCSRF
256		}
257		if err := validateSameOrigin(httpReq); err != nil {
258			return nil, err
259		}
260		presented := httpReq.Header.Get(CSRFHeaderName)
261		if r.CSRFTokens == nil || !r.CSRFTokens.Validate(presented) {
262			return nil, errCSRF
263		}
264	
265		identity := operatorPromptIdentity(httpReq)
266		if !r.canSubmit(identity) {
267			return nil, errSubmitDenied
268		}
269	
270		cap := r.PromptCapBytes
271		if cap <= 0 {
272			cap = DefaultOperatorPromptCapBytes
273		}
274		if observed := len(input.Prompt); observed > cap {
275			return nil, promptCapError(observed, cap)
276		}
277	
278		cache := r.OperatorPromptIdempotency
279		if cache == nil {
280			return nil, fmt.Errorf("operator-prompts: idempotency cache not configured")
281		}
282	
283		store := r.beadStore()
284		if id, ok := cache.Lookup(input.IdempotencyKey); ok {
285			existing, err := store.Get(id)
286			if err == nil {
287				return &OperatorPromptSubmitResult{
288					Bead:         beadModelFromBead(existing),
289					Deduplicated: true,
290				}, nil
291			}
292			// Cached ID points to a missing bead — fall through and create a
293			// fresh bead, overwriting the stale entry below.
294		}
295	
296		tier := bead.DefaultPriority
297		if input.Tier != nil {
298			tier = *input.Tier
299		}
300		b := bead.NewOperatorPromptBead(input.Prompt, tier)
301		if err := store.Create(b); err != nil {
302			return nil, err
303		}
304	
305		originNodeID := httpReq.Header.Get("X-Tailscale-Node")
306		if originNodeID == "" {
307			// Loopback callers do not carry an X-Tailscale-Node header; the
308			// origin and the receiving node are the same machine, so record the
309			// receiving node ID for symmetry.
310			originNodeID = r.NodeID
311		}
312		buildSHA := r.BuildSHA
313		if buildSHA == "" {
314			buildSHA = "unknown"
315		}
316		approvalMode := "manual"
317		if input.AutoApprove != nil && *input.AutoApprove {
318			approvalMode = "auto-requested"
319		}
320		requestID := httpReq.Header.Get("X-Request-Id")
321		if requestID == "" {
322			requestID = newRequestID()
323		}
324		promptHash := sha256.Sum256([]byte(input.Prompt))
325		promptSHA := hex.EncodeToString(promptHash[:])
326		auditBody := fmt.Sprintf(
327			"identity=%s remote_addr=%s tailscale_user=%s tailscale_node=%s "+
328				"origin_node_id=%s receiving_node_id=%s build_sha=%s "+
329				"approval_mode=%s request_id=%s prompt_sha256=%s "+
330				"idempotency_key=%s",
331			identity.kind,
332			httpReq.RemoteAddr,
333			httpReq.Header.Get("X-Tailscale-User"),
334			httpReq.Header.Get("X-Tailscale-Node"),
335			originNodeID,
336			r.NodeID,
337			buildSHA,
338			approvalMode,
339			requestID,
340			promptSHA,
341			input.IdempotencyKey,
342		)
343		if err := store.AppendEvent(b.ID, bead.BeadEvent{
344			Kind:    OperatorPromptEventKind,
345			Summary: "operator prompt submitted",
346			Body:    auditBody,
347			Actor:   identity.actor,
348			Source:  "graphql:operatorPromptSubmit",
349		}); err != nil {
350			return nil, fmt.Errorf("operator-prompts: append audit event: %w", err)
351		}
352	
353		cache.Store(input.IdempotencyKey, b.ID)
354	
355		// Auto-approve path: only when the caller asked for it AND the identity
356		// is on the per-project allowlist. ts-net identities never qualify
357		// (locked Story 15 decision). On denial we leave the bead in proposed
358		// and return autoApproved=false; the caller can still issue a manual
359		// operatorPromptApprove later from a permitted identity.
360		autoApproved := false
361		if input.AutoApprove != nil && *input.AutoApprove {
362			if r.canAutoApprove(identity) {
363				if err := store.Update(b.ID, func(updated *bead.Bead) {
364					updated.Status = bead.StatusOpen
365				}); err != nil {
366					return nil, fmt.Errorf("operator-prompts: auto-approve update: %w", err)
367				}
368				if err := store.AppendEvent(b.ID, bead.BeadEvent{
369					Kind:    OperatorPromptApproveEventKind,
370					Summary: "operator prompt auto-approved on submit",
371					Body:    fmt.Sprintf("identity=%s actor=%s", identity.kind, identity.actor),
372					Actor:   identity.actor,
373					Source:  "graphql:operatorPromptSubmit",
374				}); err != nil {
375					return nil, fmt.Errorf("operator-prompts: append auto-approve event: %w", err)
376				}
377				autoApproved = true
378			}
379		}
380	
381		// Re-read so the audit event materializes in the returned snapshot.
382		persisted, err := store.Get(b.ID)
383		if err != nil {
384			return nil, err
385		}
386		return &OperatorPromptSubmitResult{
387			Bead:         beadModelFromBead(persisted),
388			Deduplicated: false,
389			AutoApproved: autoApproved,
390		}, nil
391	}
392	
393	// OperatorPromptApprove implements the operatorPromptApprove mutation:
394	// validates CSRF, verifies the bead is a proposed operator-prompt, enforces
395	// the per-project allowlist (ts-net identities are never eligible per
396	// locked decision), transitions proposed → open, and appends an audit event
397	// recording the approver.
398	func (r *mutationResolver) OperatorPromptApprove(ctx context.Context, id string) (*OperatorPromptApproveResult, error) {
399		httpReq, ident, err := r.requireOperatorPromptCSRF(ctx)
400		if err != nil {
401			return nil, err
402		}
403		if !r.canAutoApprove(ident) {
404			return nil, errAutoApproveDenied
405		}
406	
407		store := r.beadStore()
408		existing, err := store.Get(id)
409		if err != nil {
410			return nil, err
411		}
412		if existing.IssueType != bead.IssueTypeOperatorPrompt {
413			return nil, fmt.Errorf("operator-prompts: bead %s is not an operator-prompt (issue_type=%q)", id, existing.IssueType)
414		}
415		if existing.Status != bead.StatusProposed {
416			return nil, fmt.Errorf("operator-prompts: bead %s is not in proposed status (got %q); cannot approve", id, existing.Status)
417		}
418		if err := store.Update(id, func(b *bead.Bead) {
419			b.Status = bead.StatusOpen
420		}); err != nil {
421			return nil, err
422		}
423		if err := store.AppendEvent(id, bead.BeadEvent{
424			Kind:    OperatorPromptApproveEventKind,
425			Summary: "operator prompt approved",
426			Body:    fmt.Sprintf("identity=%s actor=%s remote_addr=%s", ident.kind, ident.actor, httpReq.RemoteAddr),
427			Actor:   ident.actor,
428			Source:  "graphql:operatorPromptApprove",
429		}); err != nil {
430			return nil, fmt.Errorf("operator-prompts: append approve audit event: %w", err)
431		}
432		persisted, err := store.Get(id)
433		if err != nil {
434			return nil, err
435		}
436		return &OperatorPromptApproveResult{Bead: beadModelFromBead(persisted)}, nil
437	}
438	
439	// OperatorPromptCancel implements the operatorPromptCancel mutation:
440	// validates CSRF, verifies the bead is a proposed operator-prompt,
441	// transitions proposed → cancelled, and appends an audit event recording
442	// the canceller. Cancellation is open to any trusted identity (the
443	// allowlist gates auto-approval, not rejection) so an operator who
444	// regrets a submission can withdraw it without first being added to the
445	// approval allowlist.
446	func (r *mutationResolver) OperatorPromptCancel(ctx context.Context, id string) (*OperatorPromptCancelResult, error) {
447		httpReq, ident, err := r.requireOperatorPromptCSRF(ctx)
448		if err != nil {
449			return nil, err
450		}
451	
452		store := r.beadStore()
453		existing, err := store.Get(id)
454		if err != nil {
455			return nil, err
456		}
457		if existing.IssueType != bead.IssueTypeOperatorPrompt {
458			return nil, fmt.Errorf("operator-prompts: bead %s is not an operator-prompt (issue_type=%q)", id, existing.IssueType)
459		}
460		if existing.Status != bead.StatusProposed {
461			return nil, fmt.Errorf("operator-prompts: bead %s is not in proposed status (got %q); cannot cancel", id, existing.Status)
462		}
463		if err := store.Update(id, func(b *bead.Bead) {
464			b.Status = bead.StatusCancelled
465		}); err != nil {
466			return nil, err
467		}
468		if err := store.AppendEvent(id, bead.BeadEvent{
469			Kind:    OperatorPromptCancelEventKind,
470			Summary: "operator prompt cancelled",
471			Body:    fmt.Sprintf("identity=%s actor=%s remote_addr=%s", ident.kind, ident.actor, httpReq.RemoteAddr),
472			Actor:   ident.actor,
473			Source:  "graphql:operatorPromptCancel",
474		}); err != nil {
475			return nil, fmt.Errorf("operator-prompts: append cancel audit event: %w", err)
476		}
477		persisted, err := store.Get(id)
478		if err != nil {
479			return nil, err
480		}
481		return &OperatorPromptCancelResult{Bead: beadModelFromBead(persisted)}, nil
482	}
483	
484	// requireOperatorPromptCSRF is the shared preamble for the approve and
485	// cancel mutations. It pulls the originating *http.Request from context
486	// (the server's GraphQL handler installs it via WithHTTPRequest), enforces
487	// the CSRF token check against the configured store, and returns the
488	// classified identity.
489	func (r *mutationResolver) requireOperatorPromptCSRF(ctx context.Context) (*http.Request, operatorPromptIdentityInfo, error) {
490		if r.WorkingDir == "" {
491			return nil, operatorPromptIdentityInfo{}, fmt.Errorf("working directory not configured")
492		}
493		httpReq := httpRequestFromContext(ctx)
494		if httpReq == nil {
495			return nil, operatorPromptIdentityInfo{}, errCSRF
496		}
497		presented := httpReq.Header.Get(CSRFHeaderName)
498		if r.CSRFTokens == nil || !r.CSRFTokens.Validate(presented) {
499			return nil, operatorPromptIdentityInfo{}, errCSRF
500		}
501		return httpReq, operatorPromptIdentity(httpReq), nil
502	}
503	
504	// canSubmit reports whether ident is authorized to submit operator prompts
505	// for this project. Localhost identities are always allowed (they have
506	// already cleared the requireTrusted loopback gate, which is the project's
507	// strongest trust signal). ts-net identities must appear in the per-project
508	// OperatorPromptAutoApproveAllowlist (the same list that gates approval —
509	// per Story 15 the project's "allow_identities" config is one allowlist
510	// serving both submit-by-tsnet and approve-by-localhost). An empty list
511	// rejects every ts-net peer, yielding the documented "ts-net peers see
512	// read-only UI" default.
513	func (r *Resolver) canSubmit(ident operatorPromptIdentityInfo) bool {
514		if ident.kind == "localhost" {
515			return true
516		}
517		if ident.kind != "tsnet" {
518			return false
519		}
520		for _, entry := range r.OperatorPromptAutoApproveAllowlist {
521			if entry == ident.actor {
522				return true
523			}
524		}
525		return false
526	}
527	
528	// canAutoApprove reports whether ident is authorized to approve operator
529	// prompts under the resolver's allowlist. ts-net identities are denied
530	// unconditionally (locked Story 15 decision). For localhost identities,
531	// the literal sentinel "localhost" matches any actor; otherwise the
532	// allowlist entry must equal the identity's actor string.
533	func (r *Resolver) canAutoApprove(ident operatorPromptIdentityInfo) bool {
534		if ident.kind != "localhost" {
535			return false
536		}
537		if len(r.OperatorPromptAutoApproveAllowlist) == 0 {
538			return false
539		}
540		for _, entry := range r.OperatorPromptAutoApproveAllowlist {
541			if entry == OperatorPromptAllowlistLocalhostSentinel {
542				return true
543			}
544			if entry == ident.actor {
545				return true
546			}
547		}
548		return false
549	}
550	
551	type operatorPromptIdentityInfo struct {
552		kind  string // "tsnet" or "localhost"
553		actor string
554	}
555	
556	// operatorPromptIdentity classifies the originating identity for audit
557	// logging. ts-net peers are identified by the X-Tailscale-User header
558	// injected by tsnetMiddleware; loopback callers fall back to a
559	// "localhost:<remote-addr>" actor string. A bare "anonymous" actor is used
560	// only when neither signal is present (which should not occur because
561	// requireTrusted gates the GraphQL endpoint).
562	func operatorPromptIdentity(r *http.Request) operatorPromptIdentityInfo {
563		if user := r.Header.Get("X-Tailscale-User"); user != "" {
564			return operatorPromptIdentityInfo{kind: "tsnet", actor: user}
565		}
566		if r.RemoteAddr != "" {
567			return operatorPromptIdentityInfo{kind: "localhost", actor: "localhost:" + r.RemoteAddr}
568		}
569		return operatorPromptIdentityInfo{kind: "unknown", actor: "anonymous"}
570	}
571	
572	// validateSameOrigin enforces strict Origin/Host equality on prompt-driven
573	// mutations. When the request carries an Origin header (every browser POST
574	// does), the host portion must match the request Host — this rejects
575	// browser cross-origin POSTs even from a trusted-loopback peer (defense in
