package agent

import (
	"os"
	"path/filepath"
	"sync"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
)

// AC: "two operator prompts mutating same bead exercises land-coordinator
// conflict path with no silent corruption". This test runs two parallel
// recordOperatorPromptBacklinks calls — one per concurrent operator-prompt
// originator — both targeting the same affected bead. The bead store's
// per-bead serialisation (Update + WithLock) is the agent-side analogue of
// the land coordinator: both back-link events MUST land in order, neither
// origin's audit trail may be lost or interleaved into a malformed entry.
func TestRecordOperatorPromptBacklinks_ConcurrentTargetSameBead(t *testing.T) {
	dir := t.TempDir()
	ddxDir := filepath.Join(dir, ".ddx")
	if err := os.MkdirAll(ddxDir, 0o755); err != nil {
		t.Fatal(err)
	}
	if err := os.WriteFile(filepath.Join(ddxDir, "config.yaml"), []byte("version: \"1.0\"\nbead:\n  id_prefix: \"op\"\n"), 0o644); err != nil {
		t.Fatal(err)
	}
	store := bead.NewStore(ddxDir)
	if err := store.Init(); err != nil {
		t.Fatal(err)
	}

	originatorA := bead.NewOperatorPromptBead("prompt A", bead.DefaultPriority)
	originatorB := bead.NewOperatorPromptBead("prompt B", bead.DefaultPriority)
	if err := store.Create(originatorA); err != nil {
		t.Fatal(err)
	}
	if err := store.Create(originatorB); err != nil {
		t.Fatal(err)
	}
	target := &bead.Bead{
		ID:        "op-shared-target",
		Title:     "shared",
		Status:    bead.StatusOpen,
		IssueType: "task",
	}
	if err := store.Create(target); err != nil {
		t.Fatal(err)
	}

	var wg sync.WaitGroup
	wg.Add(2)
	now := time.Now().UTC()
	errs := make([]error, 2)
	go func() {
		defer wg.Done()
		errs[0] = recordOperatorPromptBacklinks(store, originatorA.ID, operatorPromptAffected{
			BeadIDs: []string{target.ID},
		}, "actor-a", now)
	}()
	go func() {
		defer wg.Done()
		errs[1] = recordOperatorPromptBacklinks(store, originatorB.ID, operatorPromptAffected{
			BeadIDs: []string{target.ID},
		}, "actor-b", now)
	}()
	wg.Wait()

	for i, err := range errs {
		if err != nil {
			t.Fatalf("concurrent backlink %d: %v", i, err)
		}
	}

	// Target must carry exactly two origin_operator_prompt_id events — one
	// per originator. Neither may have silently dropped (corruption).
	events, err := store.EventsByKind(target.ID, OperatorPromptBacklinkEventKind)
	if err != nil {
		t.Fatal(err)
	}
	if len(events) != 2 {
		t.Fatalf("target must carry 2 backlink events under concurrent origins, got %d", len(events))
	}
	bodies := []string{events[0].Body, events[1].Body}
	hasA, hasB := false, false
	for _, body := range bodies {
		if body == "origin_operator_prompt_id="+originatorA.ID {
			hasA = true
		}
		if body == "origin_operator_prompt_id="+originatorB.ID {
			hasB = true
		}
	}
	if !hasA || !hasB {
		t.Errorf("both originators must appear in target events; bodies=%v", bodies)
	}

	// Each originator must carry its own blast-radius summary event.
	for _, origID := range []string{originatorA.ID, originatorB.ID} {
		summaries, err := store.EventsByKind(origID, OperatorPromptBacklinkEventKind)
		if err != nil {
			t.Fatal(err)
		}
		if len(summaries) != 1 {
			t.Errorf("originator %s must carry exactly 1 summary event, got %d", origID, len(summaries))
		}
	}
}

package agent

import (
	"context"
	"testing"
	"time"
)

// AC: "Execute-loop wakes on approve event without waiting for next tick".
// sleepOrWake is the unit-level building block — when wakeCh fires before
// the timer it returns nil immediately so the loop re-scans the queue. A
// 60s sleep that returns within 50ms proves the wake path short-circuits
// the timer.
func TestSleepOrWake_WakesEarly(t *testing.T) {
	wakeCh := make(chan struct{}, 1)
	wakeCh <- struct{}{}

	start := time.Now()
	if err := sleepOrWake(context.Background(), 60*time.Second, wakeCh); err != nil {
		t.Fatalf("unexpected err: %v", err)
	}
	if elapsed := time.Since(start); elapsed > 50*time.Millisecond {
		t.Errorf("wake must short-circuit the timer; elapsed=%v", elapsed)
	}
}

// AC sanity: with a nil wakeCh the helper falls back to plain
// sleepWithContext semantics and respects the timer / context cancel.
func TestSleepOrWake_NilWakeChFallsBackToTimer(t *testing.T) {
	start := time.Now()
	if err := sleepOrWake(context.Background(), 20*time.Millisecond, nil); err != nil {
		t.Fatalf("unexpected err: %v", err)
	}
	if elapsed := time.Since(start); elapsed < 15*time.Millisecond {
		t.Errorf("nil wake must wait for the timer; elapsed=%v", elapsed)
	}
}

// AC sanity: ctx cancel still wins over the wake channel.
func TestSleepOrWake_ContextCancel(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	wakeCh := make(chan struct{})
	cancel()
	if err := sleepOrWake(ctx, 5*time.Second, wakeCh); err == nil {
		t.Error("want context.Canceled, got nil")
	}
}

package server

import (
	"testing"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
)

// AC: WakeProject signals every running execute-loop worker bound to a
// project. The send must be non-blocking — even when the worker has not
// yet received from its wake channel — and must coalesce: a second wake
// while one is still pending is dropped (cap-1 buffer).
func TestWorkerManager_WakeProject_BroadcastsAndCoalesces(t *testing.T) {
	dir := t.TempDir()
	m := NewWorkerManager(dir)

	wakeCh := make(chan struct{}, 1)
	m.workers["worker-test"] = &workerHandle{
		record: WorkerRecord{ProjectRoot: dir},
		wakeCh: wakeCh,
	}

	if got := m.WakeProject(dir); got != 1 {
		t.Errorf("first wake: want 1 worker signalled, got %d", got)
	}
	// Wake again before the channel is drained — must coalesce, not block.
	if got := m.WakeProject(dir); got != 1 {
		t.Errorf("coalesced wake: want 1, got %d", got)
	}
	// Drain — exactly one wake should be present.
	select {
	case <-wakeCh:
	default:
		t.Fatal("wake channel must have one pending signal")
	}
	select {
	case <-wakeCh:
		t.Fatal("wake must coalesce; second receive should not have a pending signal")
	default:
	}
}

// AC: WakeProject ignores workers bound to other projects.
func TestWorkerManager_WakeProject_IgnoresOtherProjects(t *testing.T) {
	m := NewWorkerManager(t.TempDir())
	otherWake := make(chan struct{}, 1)
	m.workers["other-worker"] = &workerHandle{
		record: WorkerRecord{ProjectRoot: "/some/other/project"},
		wakeCh: otherWake,
	}
	if got := m.WakeProject("/different/project"); got != 0 {
		t.Errorf("want 0 wakes for unrelated project, got %d", got)
	}
	select {
	case <-otherWake:
		t.Error("other-project worker must not be signalled")
	default:
	}
}

// AC: WakeProject is a no-op for plugin-action workers (wakeCh nil) and
// does not panic.
func TestWorkerManager_WakeProject_NilWakeChSafe(t *testing.T) {
	dir := t.TempDir()
	m := NewWorkerManager(dir)
	m.workers["plugin-worker"] = &workerHandle{
		record: WorkerRecord{ProjectRoot: dir},
		wakeCh: nil,
	}
	if got := m.WakeProject(dir); got != 0 {
		t.Errorf("plugin-action worker (nil wakeCh) must not be counted; got %d", got)
	}
}

// Compile-time guard: WorkerManager satisfies the graphql.ExecuteLoopWaker
// shape used by the resolver. We do not import the graphql package here to
// avoid a cycle, but we duplicate the signature in a local interface.
var _ interface {
	WakeProject(string) int
} = (*WorkerManager)(nil)

var _ = agent.ExecuteBeadLoopRuntime{} // ensure agent import is referenced
